fs = 44100  # rata de esantionare
dur = 0.2   # durata fiecarei note (secunde)

signal = np.array([])

for f in freqs:
    t = np.linspace(0, dur, int(fs * dur), False)
    note = np.sin(2 * np.pi * f * t)
    signal = np.concatenate((signal, note))

# normalizare
signal = signal / np.max(np.abs(signal))

sd.play(signal, fs)
sd.wait()